import { defineComponentSlotStyle } from "@yamada-ui/react"
import { nativePopoverStyle } from "../native-popover"

export const popoverStyle = defineComponentSlotStyle({
  base: {
    ...nativePopoverStyle.base,
    positioner: { zIndex: "recoome" },
  },

  sizes: nativePopoverStyle.sizes,

  defaultProps: {
    size: "md",
  },
})

export type PopoverStyle = typeof popoverStyle

import { a11y, page, render, renderHook } from "#test/browser"
import { Popover } from "."
import { Button } from "../button"
import { usePopupAnimationProps } from "./popover"

describe("<Popover />", () => {
  const Component = (props: Popover.RootProps) => {
    return (
      <Popover.Root {...props}>
        <Popover.Trigger>
          <Button>Popover Trigger</Button>
        </Popover.Trigger>

        <Popover.Content data-testid="popoverContent">
          <Popover.Header>Popover Header</Popover.Header>
          <Popover.Body>Popover Body</Popover.Body>
          <Popover.Footer>Popover Footer</Popover.Footer>
        </Popover.Content>
      </Popover.Root>
    )
  }

  const ComponentWithAnchor = (props: Popover.RootProps) => {
    return (
      <Popover.Root {...props}>
        <Popover.Anchor>
          <Button>Popover Anchor</Button>
        </Popover.Anchor>

        <Popover.Trigger>
          <Button>Popover Trigger</Button>
        </Popover.Trigger>

        <Popover.Content>
          <Popover.Header>Popover Header</Popover.Header>
          <Popover.Body>Popover Body</Popover.Body>
          <Popover.Footer>Popover Footer</Popover.Footer>
        </Popover.Content>
      </Popover.Root>
    )
  }

  const ComponentWithCloseTrigger = (props: Popover.RootProps) => {
    return (
      <Popover.Root {...props}>
        <Popover.Trigger>
          <Button>Popover Trigger</Button>
        </Popover.Trigger>

        <Popover.Content>
          <Popover.Header>Popover Header</Popover.Header>
          <Popover.Body>Popover Body</Popover.Body>
          <Popover.Footer>
            <Popover.CloseTrigger>
              <Button>Close</Button>
            </Popover.CloseTrigger>
          </Popover.Footer>
        </Popover.Content>
      </Popover.Root>
    )
  }

  test("renders component correctly", async () => {
    await a11y(<Component defaultOpen />)
  })

  test("sets `displayName` correctly", () => {
    expect(Popover.Root.name).toBe("PopoverRoot")
    expect(Popover.Trigger.displayName).toBe("PopoverTrigger")
    expect(Popover.CloseTrigger.displayName).toBe("PopoverCloseTrigger")
    expect(Popover.Anchor.displayName).toBe("PopoverAnchor")
    expect(Popover.Content.displayName).toBe("PopoverContent")
    expect(Popover.Header.displayName).toBe("PopoverHeader")
    expect(Popover.Body.displayName).toBe("PopoverBody")
    expect(Popover.Footer.displayName).toBe("PopoverFooter")
  })

  test("sets `className` correctly", async () => {
    await render(<ComponentWithAnchor defaultOpen />)
    const trigger = page.getByText("Popover Trigger").element()
    const anchor = page.getByText("Popover Anchor").element()
    const header = page.getByText("Popover Header").element()
    const body = page.getByText("Popover Body").element()
    const footer = page.getByText("Popover Footer").element()
    const content = header.parentElement
    const positioner = content?.parentElement

    expect(trigger).toHaveClass("ui-popover__trigger")
    expect(anchor).toHaveClass("ui-popover__anchor")
    expect(header).toHaveClass("ui-popover__header")
    expect(body).toHaveClass("ui-popover__body")
    expect(footer).toHaveClass("ui-popover__footer")
    expect(content).toHaveClass("ui-popover__content")
    expect(positioner).toHaveClass("ui-popover__positioner")
  })

  test("renders HTML tag correctly", async () => {
    await render(<ComponentWithAnchor defaultOpen />)
    const header = page.getByText("Popover Header").element()
    const body = page.getByText("Popover Body").element()
    const footer = page.getByText("Popover Footer").element()
    const content = header.parentElement
    const positioner = content?.parentElement

    expect(header.tagName).toBe("DIV")
    expect(body.tagName).toBe("DIV")
    expect(footer.tagName).toBe("DIV")
    expect(content?.tagName).toBe("DIV")
    expect(positioner?.tagName).toBe("DIV")
  })

  test("should close with escape key", async () => {
    const { user } = await render(<Component />)

    const triggerButton = page.getByRole("button", {
      name: "Popover Trigger",
    })

    await user.click(triggerButton)

    await expect.element(page.getByText("Popover Header")).toBeVisible()
    await expect.element(page.getByText("Popover Body")).toBeVisible()
    await expect.element(page.getByText("Popover Footer")).toBeVisible()

    const popoverContent = page.getByTestId("popoverContent").element()

    popoverContent.focus()
    await expect.poll(() => document.activeElement).toBe(popoverContent)
    await user.keyboard("{Escape}")

    await expect.poll(() => page.getByText("Popover Header").query()).toBeNull()
    await expect.poll(() => page.getByText("Popover Body").query()).toBeNull()
    await expect.poll(() => page.getByText("Popover Footer").query()).toBeNull()
  })

  test("should not close with escape key when `closeOnEsc` is false", async () => {
    const { user } = await render(<Component closeOnEsc={false} />)

    const triggerButton = page.getByRole("button", {
      name: "Popover Trigger",
    })

    await user.click(triggerButton)

    const header = page.getByText("Popover Header")
    const popoverContent = page.getByTestId("popoverContent").element()

    popoverContent.focus()
    await expect.poll(() => document.activeElement).toBe(popoverContent)
    await user.keyboard("{Escape}")

    await expect.element(header).toBeVisible()
  })

  test("should return focus to trigger after escape key", async () => {
    const { user } = await render(<Component />)

    const triggerButton = page.getByRole("button", {
      name: "Popover Trigger",
    })

    await user.click(triggerButton)

    await expect.element(page.getByText("Popover Header")).toBeVisible()

    const popoverContent = page.getByTestId("popoverContent").element()

    popoverContent.focus()
    await expect.poll(() => document.activeElement).toBe(popoverContent)
    await user.keyboard("{Escape}")

    await expect
      .poll(() => document.activeElement)
      .toBe(triggerButton.element())
  })

  test("can close on blur", async () => {
    const { user } = await render(<Component />)

    const triggerButton = page.getByRole("button", {
      name: "Popover Trigger",
    })

    await user.click(triggerButton)

    await expect.element(page.getByText("Popover Header")).toBeVisible()
    await expect.element(page.getByText("Popover Body")).toBeVisible()
    await expect.element(page.getByText("Popover Footer")).toBeVisible()

    document.body.dispatchEvent(new MouseEvent("mousedown", { bubbles: true }))
    document.body.dispatchEvent(new MouseEvent("mouseup", { bubbles: true }))
    document.body.dispatchEvent(new MouseEvent("click", { bubbles: true }))

    await expect.poll(() => page.getByText("Popover Header").query()).toBeNull()
    await expect.poll(() => page.getByText("Popover Body").query()).toBeNull()
    await expect.poll(() => page.getByText("Popover Footer").query()).toBeNull()
  })

  test("should close when close trigger is clicked", async () => {
    const { user } = await render(<ComponentWithCloseTrigger />)

    const triggerButton = page.getByRole("button", {
      name: "Popover Trigger",
    })

    await user.click(triggerButton)

    const closeButton = page.getByRole("button", {
      name: "Close",
    })

    await user.click(closeButton)

    await expect.poll(() => page.getByText("Popover Header").query()).toBeNull()
  })

  test("should return focus to trigger after close trigger is clicked", async () => {
    const { user } = await render(<ComponentWithCloseTrigger />)

    const triggerButton = page.getByRole("button", {
      name: "Popover Trigger",
    })

    await user.click(triggerButton)

    const closeButton = page.getByRole("button", {
      name: "Close",
    })

    await user.click(closeButton)

    await expect
      .poll(() => document.activeElement)
      .toBe(triggerButton.element())
  })

  test("should apply modal behavior when `modal` is true", async () => {
    const { user } = await render(<Component modal />)

    const triggerButton = page.getByRole("button", {
      name: "Popover Trigger",
    })

    await user.click(triggerButton)

    await expect
      .element(page.getByTestId("popoverContent"))
      .toHaveAttribute("aria-modal", "true")
  })

  test("should block scroll when `blockScrollOnMount` is true", async () => {
    const { user } = await render(<Component blockScrollOnMount />)

    const triggerButton = page.getByRole("button", {
      name: "Popover Trigger",
    })

    await user.click(triggerButton)

    await expect.element(page.getByText("Popover Header")).toBeVisible()

    await expect.poll(() => document.body.style.overflow).toBe("hidden")
  })

  test("should render children as function", async () => {
    const childrenFn = vi.fn(({ open }) => (
      <div data-testid="fn-child">{open ? "open" : "closed"}</div>
    ))

    await render(<Popover.Root defaultOpen>{childrenFn}</Popover.Root>)

    expect(childrenFn).toHaveBeenCalledWith(
      expect.objectContaining({ open: true }),
    )
    await expect.element(page.getByTestId("fn-child")).toHaveTextContent("open")
  })
})

describe("usePopupAnimationProps", () => {
  test("returns scale animation props by default", async () => {
    const { result } = await renderHook(() => usePopupAnimationProps())
    expect(result.current).toHaveProperty("animate", "enter")
    expect(result.current).toHaveProperty("exit", "exit")
    expect(result.current).toHaveProperty("initial", "exit")
    expect("custom" in result.current && result.current.custom).toStrictEqual({
      duration: 0.1,
      reverse: true,
      scale: 0.95,
    })
  })

  test("returns slide-fade props for `inline-end`", async () => {
    const { result } = await renderHook(() =>
      usePopupAnimationProps({ animationScheme: "inline-end" }),
    )
    expect(result.current).toHaveProperty("animate", "enter")
    expect("custom" in result.current && result.current.custom).toStrictEqual({
      duration: 0.1,
      offsetX: 16,
      reverse: true,
    })
  })

  test("returns slide-fade props for `inline-start`", async () => {
    const { result } = await renderHook(() =>
      usePopupAnimationProps({ animationScheme: "inline-start" }),
    )
    expect("custom" in result.current && result.current.custom).toStrictEqual({
      duration: 0.1,
      offsetX: -16,
      reverse: true,
    })
  })

  test("returns slide-fade props for `block-start`", async () => {
    const { result } = await renderHook(() =>
      usePopupAnimationProps({ animationScheme: "block-start" }),
    )
    expect("custom" in result.current && result.current.custom).toStrictEqual({
      duration: 0.1,
      offsetY: -16,
      reverse: true,
    })
  })

  test("returns slide-fade props for `block-end`", async () => {
    const { result } = await renderHook(() =>
      usePopupAnimationProps({ animationScheme: "block-end" }),
    )
    expect("custom" in result.current && result.current.custom).toStrictEqual({
      duration: 0.1,
      offsetY: 16,
      reverse: true,
    })
  })

  test("returns empty object for `none`", async () => {
    const { result } = await renderHook(() =>
      usePopupAnimationProps({ animationScheme: "none" }),
    )
    expect(result.current).toStrictEqual({})
  })

  test("passes custom duration", async () => {
    const { result } = await renderHook(() =>
      usePopupAnimationProps({
        animationScheme: "scale",
        duration: 0.5,
      }),
    )
    expect("custom" in result.current && result.current.custom).toStrictEqual({
      duration: 0.5,
      reverse: true,
      scale: 0.95,
    })
  })
})

"use client"

import type { FC, PropsWithChildren } from "react"
import type { HTMLProps,
  HTMLStyledProps,
  SimplePlacement,
  StyleValue,
  ThemeProps, Merge, ReactNodeOrFunction } from "@yamada-ui/react"
import type { HTMLMotionProps, MotionTransitionProps } from "../motion"
import type { PortalProps } from "../portal"
import type { PopoverStyle } from "./popover.style"
import type { UsePopoverProps, UsePopoverReturn } from "./use-popover"
import { AnimatePresence } from "motion/react"
import { useMemo } from "react"
import { createSlotComponent, cast, filterUndefined, runIfFn } from "@yamada-ui/react"
import { useValue } from "../../hooks/use-value"
import { fadeScaleVariants } from "../fade-scale"
import { motion } from "../motion"
import { Portal } from "../portal"
import { slideFadeVariants } from "../slide-fade"
import { popoverStyle } from "./popover.style"
import { usePopover } from "./use-popover"

export interface UsePopupAnimationProps {
  /**
   * The animation of the element.
   *
   * @default 'scale'
   */
  animationScheme?: StyleValue<"none" | "scale" | SimplePlacement>
  /**
   * The animation duration.
   *
   * @default 0.1
   */
  duration?: StyleValue<MotionTransitionProps["duration"]>
}

export const usePopupAnimationProps = (props: UsePopupAnimationProps = {}) => {
  const animationScheme = useValue(props.animationScheme ?? "scale")
  const duration = useValue(props.duration ?? 0.1)
  const sharedProps = { animate: "enter", exit: "exit", initial: "exit" }

  switch (animationScheme) {
    case "scale":
      return {
        ...sharedProps,
        custom: { duration, reverse: true, scale: 0.95 },
        variants: fadeScaleVariants,
      }
    case "block-start":
      return {
        ...sharedProps,
        custom: { duration, offsetY: -16, reverse: true },
        variants: slideFadeVariants,
      }
    case "inline-end":
      return {
        ...sharedProps,
        custom: { duration, offsetX: 16, reverse: true },
        variants: slideFadeVariants,
      }
    case "inline-start":
      return {
        ...sharedProps,
        custom: { duration, offsetX: -16, reverse: true },
        variants: slideFadeVariants,
      }
    case "block-end":
      return {
        ...sharedProps,
        custom: { duration, offsetY: 16, reverse: true },
        variants: slideFadeVariants,
      }
    default:
      return {}
  }
}

export interface UsePopoverStyleProps {
  /**
   * If `true`, the popper will change its placement and flip when it's about to overflow its boundary area.
   *
   * @default true
   */
  flip?: StyleValue<UsePopoverProps["flip"]>
  /**
   * The distance or margin between the reference and popper.
   * It is used internally to create an `offset` modifier.
   *
   * @default 8
   */
  gutter?: StyleValue<UsePopoverProps["gutter"]>
  /**
   * If `true`, the popper will match the width of the reference at all times.
   * It's useful for `autocomplete`, `date-picker` and `select` patterns.
   *
   * @default false
   */
  matchWidth?: StyleValue<UsePopoverProps["matchWidth"]>
  /**
   * The placement of the popper relative to its reference.
   *
   * @default 'end'
   */
  placement?: StyleValue<UsePopoverProps["placement"]>
  /**
   * The CSS positioning strategy to use.
   *
   * @default 'absolute'
   */
  strategy?: StyleValue<UsePopoverProps["strategy"]>
}

export const usePopoverStyleProps = (props: UsePopoverStyleProps = {}) => {
  const placement = useValue(props.placement)
  const gutter = useValue(props.gutter)
  const matchWidth = useValue(props.matchWidth)
  const strategy = useValue(props.strategy)
  const flip = useValue(props.flip)

  return useMemo(
    () => filterUndefined({ flip, gutter, matchWidth, placement, strategy }),
    [flip, gutter, matchWidth, placement, strategy],
  )
}

interface ComponentContext
  extends
    Pick<
      UsePopoverReturn,
      | "getAnchorProps"
      | "getBodyProps"
      | "getCloseTriggerProps"
      | "getContentProps"
      | "getFooterProps"
      | "getHeaderProps"
      | "getPositionerProps"
      | "getTriggerProps"
      | "open"
    >,
    UsePopupAnimationProps {}

export interface PopoverRootProps
  extends
    Merge<UsePopoverProps, UsePopoverStyleProps>,
    UsePopupAnimationProps,
    ThemeProps<PopoverStyle> {
  /**
   * The children of the popover.
   */
  children?: ReactNodeOrFunction<{
    open: boolean
    onClose: () => void
  }>
}

const {
  ComponentContext,
  PropsContext: PopoverPropsContext,
  StyleContext,
  useComponentContext,
  usePropsContext: usePopoverPropsContext,
  withContext,
  useRootComponentProps,
} = createSlotComponent<PopoverRootProps, PopoverStyle, ComponentContext>(
  "popover",
  popoverStyle,
)

export { PopoverPropsContext, usePopoverPropsContext }

/**
 * `Popover` is a component that floats around an element to display information.
 *
 * @see https://yamada-ui.com/docs/components/popover
 */
export const PopoverRoot: FC<PopoverRootProps> = (props) => {
  const styleProps = usePopoverStyleProps(props)
  const [styleContext, { animationScheme, children, duration, ...rest }] =
    useRootComponentProps({ ...props, ...styleProps })
  const {
    open,
    getAnchorProps,
    getBodyProps,
    getCloseTriggerProps,
    getContentProps,
    getFooterProps,
    getHeaderProps,
    getPositionerProps,
    getTriggerProps,
    onClose,
  } = usePopover(rest)
  const componentContext = useMemo(
    () => ({
      animationScheme,
      duration,
      open,
      getAnchorProps,
      getBodyProps,
      getCloseTriggerProps,
      getContentProps,
      getFooterProps,
      getHeaderProps,
      getPositionerProps,
      getTriggerProps,
    }),
    [
      open,
      animationScheme,
      duration,
      getAnchorProps,
      getBodyProps,
      getCloseTriggerProps,
      getContentProps,
      getFooterProps,
      getHeaderProps,
      getPositionerProps,
      getTriggerProps,
    ],
  )

  return (
    <StyleContext value={styleContext}>
      <ComponentContext value={componentContext}>
        {runIfFn(children, { open, onClose })}
      </ComponentContext>
    </StyleContext>
  )
}

export interface PopoverTriggerProps extends HTMLStyledProps<"button"> {}

export const PopoverTrigger = withContext<"button", PopoverTriggerProps>(
  "button",
  "trigger",
)({ asChild: true }, (props) => {
  const { getTriggerProps } = useComponentContext()

  return getTriggerProps(props)
})

export interface PopoverCloseTriggerProps extends HTMLStyledProps<"button"> {}

export const PopoverCloseTrigger = withContext<
  "button",
  PopoverCloseTriggerProps
>("button", { name: "CloseTrigger", slot: ["trigger", "close"] })(
  { asChild: true },
  (props) => {
    const { getCloseTriggerProps } = useComponentContext()

    return getCloseTriggerProps(props)
  },
)

export interface PopoverAnchorProps extends HTMLStyledProps {}

export const PopoverAnchor = withContext<"div", PopoverAnchorProps>(
  "div",
  "anchor",
)({ asChild: true }, (props) => {
  const { getAnchorProps } = useComponentContext()

  return getAnchorProps(props)
})

interface PopoverPositionerProps extends HTMLStyledProps {}

const PopoverPositioner = withContext<"div", PopoverPositionerProps>(
  "div",
  "positioner",
)(undefined, (props) => {
  const { getPositionerProps } = useComponentContext()

  return getPositionerProps(props)
})

export interface PopoverContentProps
  extends Omit<HTMLMotionProps, "children">, PropsWithChildren {
  /**
   * Props for portal component.
   */
  portalProps?: Omit<PortalProps, "children">
}

export const PopoverContent = withContext<"div", PopoverContentProps>(
  ({ portalProps, ...rest }) => {
    const { animationScheme, duration, open, getContentProps } =
      useComponentContext()
    const popupAnimationProps = usePopupAnimationProps({
      animationScheme,
      duration,
    })

    return (
      <AnimatePresence>
        {open ? (
          <Portal {...portalProps}>
            <PopoverPositioner>
              <motion.div
                {...popupAnimationProps}
                {...cast<HTMLMotionProps>(
                  getContentProps(cast<HTMLProps>(rest)),
                )}
              />
            </PopoverPositioner>
          </Portal>
        ) : null}
      </AnimatePresence>
    )
  },
  "content",
)()

export interface PopoverHeaderProps extends HTMLStyledProps {}

export const PopoverHeader = withContext<"div", PopoverHeaderProps>(
  "div",
  "header",
)(undefined, (props) => {
  const { getHeaderProps } = useComponentContext()

  return getHeaderProps(props)
})

export interface PopoverBodyProps extends HTMLStyledProps {}

export const PopoverBody = withContext<"div", PopoverBodyProps>("div", "body")(
  undefined,
  (props) => {
    const { getBodyProps } = useComponentContext()

    return getBodyProps(props)
  },
)

export interface PopoverFooterProps extends HTMLStyledProps {}

export const PopoverFooter = withContext<"div", PopoverFooterProps>(
  "div",
  "footer",
)(undefined, (props) => {
  const { getFooterProps } = useComponentContext()

  return getFooterProps(props)
})

"use client"

import type { FocusEvent, KeyboardEvent, RefObject } from "react"
import type { Direction, PropGetter, Dict } from "@yamada-ui/react"
import type { UseDisclosureProps } from "../../hooks/use-disclosure"
import type { UsePopperProps } from "../../hooks/use-popper"
import type { UsePopupAnimationProps } from "./popover"
import { useCallback, useEffect, useId, useRef } from "react"
import {
  useEnvironment,
  useSplitProps,
  ariaAttr,
  assignRef,
  contains,
  dataAttr,
  focusTransfer,
  focusTrap,
  getEventRelatedTarget,
  handlerAll,
  mergeRefs,
  runKeyAction,
  scrollLock,
  setAttribute,
  useSafeLayoutEffect,
  useUnmountEffect,
} from "@yamada-ui/react"
import { useDisclosure } from "../../hooks/use-disclosure"
import { useEventListener } from "../../hooks/use-event-listener"
import { useFocusOnShow } from "../../hooks/use-focus"
import { useOutsideClick } from "../../hooks/use-outside-click"
import { popperProps, usePopper } from "../../hooks/use-popper"

export interface UsePopoverProps
  extends Omit<UseDisclosureProps, "timing">, UsePopperProps<"button"> {
  /**
   * If `true`, focus will be transferred to the first interactive element when the popover opens.
   *
   * @default true
   */
  autoFocus?: boolean
  /**
   * If `true`, scrolling will be disabled on the `body` when the modal opens.
   *
   * @default false
   */
  blockScrollOnMount?: boolean
  /**
   * If `true`, the popover will close when you blur out it by clicking outside or tabbing out.
   *
   * @default true
   */
  closeOnBlur?: boolean
  /**
   * If `true`, the popover will hide on pressing Esc key.
   *
   * @default true
   */
  closeOnEsc?: boolean
  /**
   * If `true`, the popover will hide on scroll.
   *
   * @default false
   */
  closeOnScroll?: boolean
  /**
   * If `true`, the popover will be disabled.
   *
   * @default false
   */
  disabled?: boolean
  /**
   * The `ref` of the element that should receive focus when the popover opens.
   */
  initialFocusRef?: RefObject<HTMLElement | null>
  /**
   * If `true`, the popover will be modal.
   *
   * - scrolling is blocked.
   * - focus is trapped within the popover.
   *
   * @default false
   */
  modal?: boolean
  /**
   * If `true`, the popover will be opened when click on the field.
   *
   * @default true
   */
  openOnClick?: boolean
  /**
   * The placement of the popper relative to its reference.
   *
   * @default 'end'
   */
  placement?: Direction
  /**
   * If `true`, the focus will be transferred to the popover content when the tab key is pressed.
   *
   * @default true
   */
  transferFocus?: boolean
  /**
   * Update the position of the floating element, re-rendering the component if required.
   */
  updateRef?: RefObject<() => void>
}

export const usePopover = ({
  autoFocus = true,
  autoUpdate,
  modal = false,
  blockScrollOnMount = modal,
  closeOnBlur = true,
  closeOnEsc = true,
  closeOnScroll,
  defaultOpen,
  disabled,
  elements,
  flip,
  gutter,
  initialFocusRef,
  matchWidth,
  middleware,
  offset,
  open: openProp,
  openOnClick = true,
  placement = "end",
  platform,
  preventOverflow,
  strategy,
  transferFocus = true,
  transform,
  updateRef,
  whileElementsMounted,
  onClose: onCloseProp,
  onOpen: onOpenProp,
}: UsePopoverProps = {}) => {
  const { getDocument } = useEnvironment()
  const headerId = useId()
  const bodyId = useId()
  const contentId = useId()
  const anchorRef = useRef<HTMLElement>(null)
  const triggerRef = useRef<HTMLButtonElement>(null)
  const contentRef = useRef<HTMLElement>(null)
  const openTimeout = useRef<NodeJS.Timeout>(undefined)
  const closeTimeout = useRef<NodeJS.Timeout>(undefined)
  const { open, onClose, onOpen } = useDisclosure({
    defaultOpen,
    open: openProp,
    onClose: onCloseProp,
    onOpen: onOpenProp,
  })
  const { refs, update, getPopperProps } = usePopper<"button">({
    autoUpdate,
    elements,
    flip,
    gutter,
    matchWidth,
    middleware,
    offset,
    open,
    placement,
    platform,
    preventOverflow,
    strategy,
    transform,
    whileElementsMounted,
  })

  assignRef(updateRef, update)

  const onKeyDown = useCallback(
    (ev: KeyboardEvent<HTMLElement>) => {
      runKeyAction(ev, {
        Escape: () => {
          if (!closeOnEsc) return

          onClose()

          triggerRef.current?.focus()
        },
      })
    },
    [closeOnEsc, onClose],
  )

  const onBlur = useCallback(
    (ev: FocusEvent<HTMLDivElement>) => {
      const relatedTarget = getEventRelatedTarget(ev)
      const popup = relatedTarget?.hasAttribute("data-popup")

      if (contains(triggerRef.current, relatedTarget)) return
      if (contains(contentRef.current, relatedTarget)) return
      if (contains(contentRef.current, ev.target) && popup) return

      if (closeOnBlur) onClose()
    },
    [closeOnBlur, onClose],
  )

  useEventListener(getDocument(), "scroll", () => {
    if (open && closeOnScroll) onClose()
  })

  useFocusOnShow(contentRef, {
    focusTarget: initialFocusRef,
    shouldFocus: autoFocus,
    visible: open,
  })

  useOutsideClick({
    ref: [contentRef, triggerRef],
    enabled: open && closeOnBlur,
    handler: onClose,
  })

  useSafeLayoutEffect(() => {
    const el = contentRef.current
    const hasHeader = !!getDocument()?.getElementById(headerId)
    const hasBody = !!getDocument()?.getElementById(bodyId)

    if (el && hasHeader) setAttribute(el, "aria-labelledby", headerId)
    if (el && hasBody) setAttribute(el, "aria-describedby", bodyId)
  }, [open, headerId, bodyId])

  useEffect(() => {
    if (!open || !modal) return

    return focusTrap(contentRef.current)
  }, [open, modal])

  useEffect(() => {
    if (!open || !blockScrollOnMount) return

    return scrollLock(contentRef.current)
  }, [open, modal, blockScrollOnMount])

  useEffect(() => {
    if (!open || modal || !transferFocus) return

    return focusTransfer(contentRef.current, triggerRef.current)
  }, [open, modal, transferFocus])

  useUnmountEffect(() => {
    clearTimeout(openTimeout.current)
    clearTimeout(closeTimeout.current)
  })

  const getTriggerProps: PropGetter<"button"> = useCallback(
    ({ ref, ...props } = {}) => ({
      "aria-controls": open ? contentId : undefined,
      "aria-disabled": ariaAttr(disabled),
      "aria-expanded": open,
      "aria-haspopup": "dialog",
      role: "button",
      ...props,
      ref: mergeRefs(ref, triggerRef, (node) => {
        if (anchorRef.current == null) refs.setReference(node)
      }),
      onBlur: handlerAll(props.onBlur, (ev) =>
        !contains(contentRef.current, getEventRelatedTarget(ev)) && closeOnBlur
          ? onClose()
          : void 0,
      ),
      onClick: handlerAll(
        props.onClick,
        !open ? (!disabled && openOnClick ? onOpen : undefined) : onClose,
      ),
      onKeyDown: handlerAll(props.onKeyDown, onKeyDown),
    }),
    [
      closeOnBlur,
      contentId,
      disabled,
      onClose,
      onKeyDown,
      onOpen,
      open,
      openOnClick,
      refs,
    ],
  )

  const getAnchorProps: PropGetter = useCallback(
    ({ ref, ...props } = {}) => ({
      ...props,
      ref: mergeRefs(ref, anchorRef, refs.setReference),
    }),
    [refs.setReference],
  )

  const getPositionerProps: PropGetter = useCallback(
    (props) => getPopperProps(props),
    [getPopperProps],
  )

  const getContentProps: PropGetter = useCallback(
    ({ ref, ...props } = {}) => ({
      id: contentId,
      "aria-hidden": !open,
      "aria-modal": modal ? "true" : undefined,
      "data-close": dataAttr(!open),
      "data-open": dataAttr(open),
      "data-popup": dataAttr(true),
      role: "dialog",
      tabIndex: -1,
      ...props,
      ref: mergeRefs(ref, contentRef),
      onBlur: handlerAll(props.onBlur, onBlur),
      onKeyDown: handlerAll(props.onKeyDown, onKeyDown),
    }),
    [contentId, open, modal, onBlur, onKeyDown],
  )

  const getHeaderProps: PropGetter = useCallback(
    (props) => ({ id: headerId, ...props }),
    [headerId],
  )

  const getBodyProps: PropGetter = useCallback(
    (props) => ({ id: bodyId, ...props }),
    [bodyId],
  )

  const getFooterProps: PropGetter = useCallback((props) => ({ ...props }), [])

  const getCloseTriggerProps: PropGetter<"button"> = useCallback(
    (props = {}) => ({
      ...props,
      onClick: handlerAll(props.onClick, () => {
        onClose()

        triggerRef.current?.focus()
      }),
    }),
    [onClose],
  )

  return {
    open,
    getAnchorProps,
    getBodyProps,
    getCloseTriggerProps,
    getContentProps,
    getFooterProps,
    getHeaderProps,
    getPositionerProps,
    getTriggerProps,
    onClose,
    onOpen,
  }
}

export type UsePopoverReturn = ReturnType<typeof usePopover>

export const popoverProps: (
  | keyof UsePopoverProps
  | keyof UsePopupAnimationProps
)[] = [
  ...popperProps,
  "autoFocus",
  "transferFocus",
  "blockScrollOnMount",
  "closeOnBlur",
  "closeOnEsc",
  "closeOnScroll",
  "openOnClick",
  "disabled",
  "initialFocusRef",
  "modal",
  "updateRef",
  "defaultOpen",
  "onOpen",
  "onClose",
  "animationScheme",
  "duration",
]

export const usePopoverProps = <
  Y extends Dict = Dict,
  M extends keyof UsePopoverProps | keyof UsePopupAnimationProps =
    | keyof UsePopoverProps
    | keyof UsePopupAnimationProps,
>(
  props: Y,
  omitKeys?: M[],
) => {
  return useSplitProps(
    props,
    popoverProps.filter((key) => !omitKeys?.includes(key as M)),
  ) as unknown as [
    keyof UsePopoverProps | keyof UsePopupAnimationProps extends M
      ? UsePopoverProps & UsePopupAnimationProps
      : Omit<UsePopoverProps & UsePopupAnimationProps, M>,
    Omit<
      Y,
      keyof UsePopoverProps | keyof UsePopupAnimationProps extends M
        ? keyof UsePopoverProps | keyof UsePopupAnimationProps
        : Exclude<keyof UsePopoverProps | keyof UsePopupAnimationProps, M>
    >,
  ]
}
